import React from 'react';
import { Trash2, ShoppingBag, AlertCircle, ArrowRight } from 'lucide-react';
import { useCart } from '../context/CartContext';

const Carrito = ({ onCheckout }) => {
  const { cart, removeFromCart, total, clearCart } = useCart();

  const handleFinalizarCompra = () => {
    if (cart.length === 0) return;
    onCheckout(total);
  };

  if (cart.length === 0) {
    return (
      <div style={emptyContainer}>
        <div style={iconCircle}>
            <ShoppingBag size={48} color="#e67e22" />
        </div>
        <h3 style={{ color: '#1e293b', marginTop: '20px', marginBottom: '10px' }}>Tu carrito está vacío</h3>
        <p style={{ color: '#64748b', maxWidth: '250px' }}>¡Explora las mejores ofertas cerca de ti y llena tu bolsa!</p>
      </div>
    );
  }

  return (
    <div style={container}>
      <div style={header}>
        <h2 style={{ margin: 0, fontSize: '1.4rem', color: '#1e293b' }}>Resumen de Pedido</h2>
        <button onClick={clearCart} style={btnClear}>Vaciar carrito</button>
      </div>

      <div style={listContainer}>
        {cart.map((item) => (
          <div key={item.idCarrito} style={cardItem}>
            <img 
              src={item.imagenUrl || "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=200"} 
              alt={item.producto} 
              style={imgThumb} 
            />
            <div style={{ flex: 1, marginLeft: '15px' }}>
              <h4 style={itemTitle}>{item.producto}</h4>
              <p style={itemLocal}>{item.local?.nombre || "Local Asociado"}</p>
              <div style={priceTag}>${item.precio}</div>
            </div>
            <button 
              onClick={() => removeFromCart(item.idCarrito)} 
              style={btnDelete}
              title="Quitar producto"
            >
              <Trash2 size={18} />
            </button>
          </div>
        ))}
      </div>

      <div style={footer}>
        <div style={resumenRow}>
          <span>Subtotal</span>
          <span style={valText}>${total}</span>
        </div>
        <div style={resumenRow}>
          <span>Envío domicilio</span>
          <span style={{ color: '#27ae60', fontWeight: 'bold' }}>¡GRATIS!</span>
        </div>
        <div style={divider} />
        <div style={totalRow}>
          <span>Total a pagar</span>
          <span>${total}</span>
        </div>

        <div style={infoBanner}>
          <AlertCircle size={18} color="#3182ce" />
          <small style={{lineHeight: '1.4'}}>Pagás al recibir el pedido. Tené el efectivo listo para el repartidor.</small>
        </div>

        <button onClick={handleFinalizarCompra} style={btnCheckout}>
          Confirmar Pedido <ArrowRight size={20} />
        </button>
      </div>
    </div>
  );
};

// --- ESTILOS ---
const container = { background: 'white', borderRadius: '28px', padding: '30px', boxShadow: '0 20px 40px rgba(0,0,0,0.08)', border: '1px solid #f1f5f9' };
const iconCircle = { width: '100px', height: '100px', background: '#fff3e0', borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center' };
const emptyContainer = { display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: '80px 20px', textAlign: 'center' };
const header = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' };
const btnClear = { background: 'none', border: 'none', color: '#ef4444', cursor: 'pointer', fontSize: '0.85rem', fontWeight: '700', textTransform: 'uppercase' };
const listContainer = { maxHeight: '380px', overflowY: 'auto', marginBottom: '25px', paddingRight: '10px' };
const cardItem = { display: 'flex', alignItems: 'center', padding: '15px 0', borderBottom: '1px solid #f1f5f9' };
const imgThumb = { width: '70px', height: '70px', borderRadius: '16px', objectFit: 'cover', border: '1px solid #f1f5f9' };
const itemTitle = { margin: 0, fontSize: '0.95rem', fontWeight: '700', color: '#1e293b' };
const itemLocal = { margin: '2px 0', fontSize: '0.8rem', color: '#94a3b8' };
const priceTag = { fontWeight: '800', color: '#e67e22', marginTop: '6px', fontSize: '1rem' };
const btnDelete = { background: '#fef2f2', border: 'none', padding: '10px', borderRadius: '12px', color: '#ef4444', cursor: 'pointer' };
const footer = { marginTop: '10px', padding: '25px', background: '#f8fafc', borderRadius: '22px' };
const resumenRow = { display: 'flex', justifyContent: 'space-between', color: '#64748b', marginBottom: '10px', fontSize: '0.9rem' };
const valText = { color: '#1e293b', fontWeight: '600' };
const totalRow = { display: 'flex', justifyContent: 'space-between', fontSize: '1.3rem', fontWeight: '800', color: '#1e293b', margin: '15px 0' };
const divider = { height: '1px', background: '#e2e8f0', margin: '15px 0' };
const infoBanner = { display: 'flex', alignItems: 'flex-start', gap: '10px', color: '#2b6cb0', marginBottom: '20px', background: '#ebf8ff', padding: '15px', borderRadius: '14px', border: '1px solid #bee3f8' };
const btnCheckout = { width: '100%', padding: '18px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '18px', fontSize: '1rem', fontWeight: 'bold', cursor: 'pointer', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '10px', boxShadow: '0 10px 15px -3px rgba(30, 41, 59, 0.2)' };

export default Carrito;
